UPDATE articles SET content = '[{"id":"j1","type":"paragraph","text":"Топливо, которое добывается в **Виртуальных нефтекачках**, требуется для работы **Виртуальных карьеров**."},{"id":"j2","type":"heading2","text":"⛽ Применение — заправка карьера"},{"id":"j3","type":"step","stepNum":1,"text":"Откройте вкладку **Виртуальных карьеров** в **Личном меню** (`/m`)"},{"id":"j4","type":"image","src":"https://cdn.poehali.dev/projects/21c5f7f9-6172-405c-820b-334660b805c6/bucket/wiki/20260102/530294302d304b02a0d35c4ca64392fc.png","caption":"Вкладка Виртуальных карьеров"},{"id":"j5","type":"step","stepNum":2,"text":"Откройте **топливный бак** карьера"},{"id":"j6","type":"image","src":"https://cdn.poehali.dev/projects/21c5f7f9-6172-405c-820b-334660b805c6/bucket/wiki/20260102/5cb825d4a9514291911fc7fa5bc6d8b6.png","caption":"Топливный бак карьера"},{"id":"j7","type":"step","stepNum":3,"text":"Переместите топливо в бак для заправки виртуальных карьеров"},{"id":"j8","type":"image","src":"https://cdn.poehali.dev/projects/21c5f7f9-6172-405c-820b-334660b805c6/bucket/wiki/20260102/b39f563620f04f84b16dc5d0d1a1bb3e.png","caption":"Перемещение топлива"},{"id":"j9","type":"step","stepNum":4,"text":"Запустите карьер нажав на кнопку запуска"},{"id":"j10","type":"image","src":"https://cdn.poehali.dev/projects/21c5f7f9-6172-405c-820b-334660b805c6/bucket/wiki/20260102/b5e62bf7f7494bf08f867267b2146949.png","caption":"Кнопка запуска карьера"},{"id":"j11","type":"divider"},{"id":"j12","type":"heading2","text":"📍 Где найти топливо"},{"id":"j13","type":"paragraph","text":"Найти карьерное топливо можно в **красных топливных бочках** на карте:"},{"id":"j14","type":"image","src":"https://cdn.poehali.dev/projects/21c5f7f9-6172-405c-820b-334660b805c6/bucket/wiki/20260102/e2e5bac7ff0343f6bb10d6d79a745718.png","caption":"Красные топливные бочки на карте"},{"id":"j15","type":"tip","icon":"Бочка карьерного топлива","text":"В бочках с небольшим шансом можно найти **«Бочку карьерного топлива»** — нажмите на неё в инвентаре и кликните **«Открыть сумку»** чтобы получить топливо."},{"id":"j16","type":"image","src":"https://cdn.poehali.dev/projects/21c5f7f9-6172-405c-820b-334660b805c6/bucket/wiki/20260102/f0762e0d5db54cba98beab10b93e0c92.png","caption":"Бочка карьерного топлива в инвентаре"}]' WHERE id = 8;
